import{c as l,Q as e,j as i,m as t}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse(`{"title":"I FOUND 1,116 CLAUDE CODE SKILLS FROM 500+ REPOS SO YOU DON'T HAVE TO — @polydao","description":"","frontmatter":{"title":"I FOUND 1,116 CLAUDE CODE SKILLS FROM 500+ REPOS SO YOU DON'T HAVE TO — @polydao","author":"polydao（@polydao）","date":"2026-04-24T00:00:00.000Z","source":"https://x.com/polydao/status/2047644016632557700","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-24-@polydao-557700.md","filePath":"research/tweets/2026-04-24-@polydao-557700.md","lastUpdated":1779894392000}`),s={name:"research/tweets/2026-04-24-@polydao-557700.md"};function r(o,a,n,d,c,h){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="i-found-1-116-claude-code-skills-from-500-repos-so-you-don-t-have-to-—-polydao" tabindex="-1">I FOUND 1,116 CLAUDE CODE SKILLS FROM 500+ REPOS SO YOU DON&#39;T HAVE TO — @polydao <a class="header-anchor" href="#i-found-1-116-claude-code-skills-from-500-repos-so-you-don-t-have-to-—-polydao" aria-label="Permalink to &quot;I FOUND 1,116 CLAUDE CODE SKILLS FROM 500+ REPOS SO YOU DON&#39;T HAVE TO — @polydao&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/polydao/status/2047644016632557700" target="_blank" rel="noreferrer">https://x.com/polydao/status/2047644016632557700</a><strong>作者</strong>：polydao（@polydao） <strong>發布日期</strong>：2026-04-24 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：813 likes · 90 retweets · 3,641 bookmarks · 760,583 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><blockquote><p>1,116 skills from 500+ repositories, 200+ authors</p></blockquote><p>Most people use Claude Code like a fancy autocomplete. They don&#39;t know Skills exist.</p><p>作者花費一個月整理 500+ repositories 和 200+ 作者，繪製 Claude Code Skills 生態系完整地圖。</p><h3 id="part-1-official-anthropic-skills" tabindex="-1">Part 1: Official Anthropic Skills <a class="header-anchor" href="#part-1-official-anthropic-skills" aria-label="Permalink to &quot;Part 1: Official Anthropic Skills&quot;">​</a></h3><p>Repo: github.com/anthropics/skills (121,000 stars) — 17 skills</p><ul><li>Document Generation: docx, pdf, pptx, xlsx</li><li>Development: frontend-design, webapp-testing, claude-api</li><li>MCP &amp; Meta: mcp-builder, skill-creator</li><li>Enterprise: doc-coauthoring, brand-guidelines, internal-comms</li><li>Creative: algorithmic-art, canvas-design, theme-factory, web-artifacts-builder, slack-gif-creator</li></ul><h3 id="part-2-verified-partner-skills" tabindex="-1">Part 2: Verified Partner Skills <a class="header-anchor" href="#part-2-verified-partner-skills" aria-label="Permalink to &quot;Part 2: Verified Partner Skills&quot;">​</a></h3><h4 id="sentry-—-30-skills" tabindex="-1">Sentry — 30 skills <a class="header-anchor" href="#sentry-—-30-skills" aria-label="Permalink to &quot;Sentry — 30 skills&quot;">​</a></h4><p>Repo: github.com/getsentry/sentry-for-ai (2,500+ stars)</p><h4 id="cloudflare-—-16-skills" tabindex="-1">Cloudflare — 16+ skills <a class="header-anchor" href="#cloudflare-—-16-skills" aria-label="Permalink to &quot;Cloudflare — 16+ skills&quot;">​</a></h4><p>Repo: github.com/cloudflare/skills (923 stars) — Workers, D1, R2, KV, Durable Objects, Agents SDK, Workflows, Queues, Pages</p><h4 id="trail-of-bits-—-29-skills" tabindex="-1">Trail of Bits — 29 skills <a class="header-anchor" href="#trail-of-bits-—-29-skills" aria-label="Permalink to &quot;Trail of Bits — 29 skills&quot;">​</a></h4><p>Repo: github.com/trailofbits/skills (4,700+ stars) — static-analysis, variant-analysis, semgrep-rule-creator, insecure-defaults, differential-review, sharp-edges</p><h4 id="microsoft-—-133-skills" tabindex="-1">Microsoft — 133 skills <a class="header-anchor" href="#microsoft-—-133-skills" aria-label="Permalink to &quot;Microsoft — 133 skills&quot;">​</a></h4><p>Repo: github.com/MicrosoftDocs/Agent-Skills (495 stars)</p><ul><li>.NET (25)、Java (30)、Python (40+)、Rust (7)、TypeScript (22)、Core (9)</li><li>Core 包含：cloud-solution-architect, copilot-sdk, entra-agent-id, frontend-design-review, github-issue-creator, mcp-builder, podcast-generation, skill-creator</li></ul><h4 id="其他工具廠商" tabindex="-1">其他工具廠商 <a class="header-anchor" href="#其他工具廠商" aria-label="Permalink to &quot;其他工具廠商&quot;">​</a></h4><ul><li>HashiCorp: Terraform skills — github.com/hashicorp/skills</li><li>Firecrawl: Web scraping skills (3,000+ stars) — github.com/firecrawl/firecrawl-claude-plugin</li><li>AWS: Serverless, Amplify, databases (595 stars) — github.com/awslabs/agent-plugins</li><li>Azure: MCP Server — github.com/microsoft/azure-skills</li><li>DigitalOcean、Neon、Supabase 等</li></ul><h3 id="part-3-mega-collections" tabindex="-1">Part 3: Mega Collections <a class="header-anchor" href="#part-3-mega-collections" aria-label="Permalink to &quot;Part 3: Mega Collections&quot;">​</a></h3><h4 id="obra-superpowers-—-20-skills" tabindex="-1">obra/superpowers — 20 skills <a class="header-anchor" href="#obra-superpowers-—-20-skills" aria-label="Permalink to &quot;obra/superpowers — 20 skills&quot;">​</a></h4><p>/test-driven-development, systematic-debugging, verification-before-completion, brainstorming, write-plan, execute-plan 等</p><h4 id="alirezarezvani-claude-skills-—-235-skills-最大社群-collection" tabindex="-1">alirezarezvani/claude-skills — 235 skills（最大社群 collection） <a class="header-anchor" href="#alirezarezvani-claude-skills-—-235-skills-最大社群-collection" aria-label="Permalink to &quot;alirezarezvani/claude-skills — 235 skills（最大社群 collection）&quot;">​</a></h4><h4 id="wshobson-agents-—-150-skills" tabindex="-1">wshobson/agents — 150 skills <a class="header-anchor" href="#wshobson-agents-—-150-skills" aria-label="Permalink to &quot;wshobson/agents — 150 skills&quot;">​</a></h4><h4 id="mattpocock-skills-—-17-skills" tabindex="-1">mattpocock/skills — 17 skills <a class="header-anchor" href="#mattpocock-skills-—-17-skills" aria-label="Permalink to &quot;mattpocock/skills — 17 skills&quot;">​</a></h4><p>tdd, triage-issue, request-refactor-plan, setup-pre-commit, git-guardrails, to-prd, improve-codebase</p><h4 id="neolabhq-context-engineering-kit-—-13-plugins" tabindex="-1">NeoLabHQ/context-engineering-kit — 13 plugins <a class="header-anchor" href="#neolabhq-context-engineering-kit-—-13-plugins" aria-label="Permalink to &quot;NeoLabHQ/context-engineering-kit — 13 plugins&quot;">​</a></h4><p>tdd, sdd, code-review, reflexion, sadd, ddd, kaizen, git, customize-agent, docs, tech-stack, mcp</p><h4 id="jeffallan-claude-skills-—-66-skills" tabindex="-1">jeffallan/claude-skills — 66 skills <a class="header-anchor" href="#jeffallan-claude-skills-—-66-skills" aria-label="Permalink to &quot;jeffallan/claude-skills — 66 skills&quot;">​</a></h4><p>devops-engineer, sre-engineer, terraform-engineer, kubernetes-specialist, monitoring-expert, cloud-architect</p><h4 id="forrestchang-karpathy-skills" tabindex="-1">forrestchang/karpathy-skills <a class="header-anchor" href="#forrestchang-karpathy-skills" aria-label="Permalink to &quot;forrestchang/karpathy-skills&quot;">​</a></h4><h3 id="part-4-13-按領域分類的-skills" tabindex="-1">Part 4-13: 按領域分類的 Skills <a class="header-anchor" href="#part-4-13-按領域分類的-skills" aria-label="Permalink to &quot;Part 4-13: 按領域分類的 Skills&quot;">​</a></h3><ul><li>Part 4: Core Development（方法論、Code Review、Testing、Debugging、Git、Architecture、AI/ML）</li><li>Part 5: Security &amp; Compliance（Trail of Bits, OWASP, compliance）</li><li>Part 6: DevOps &amp; Infrastructure（Terraform, Docker, K8s, Cloud, DB, CI/CD, Monitoring）</li><li>Part 7: Product &amp; Project Management</li><li>Part 8: Marketing &amp; Growth（SEO, GEO）</li><li>Part 9: Business &amp; Finance</li><li>Part 10: Design &amp; Creative（Video, 3D, Game Dev）</li><li>Part 11: Data &amp; Research</li><li>Part 12: Automation &amp; Productivity</li><li>Part 13: Specialized Domains（Education, Home Automation, Health, Niche Languages）</li></ul><blockquote><p>The people who install these now and build their workflows around them will have a compounding advantage over everyone who finds out later. That&#39;s always how it works with new tooling.</p></blockquote><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：目前最完整的 Claude Code Skills 生態系地圖，1,116 個 skills 來自 500+ repo，分 13 個領域，附所有 GitHub 連結，是 Skills 探索與安裝的一站式索引。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Skills 是 Claude Code 最被低估的功能：大多數使用者不知道 Skills 存在，直接損失生產力</li><li>官方 + 合作夥伴 (Microsoft 133 skills、Sentry 30、Trail of Bits 29、Cloudflare 16) 已是企業級成熟度</li><li>alirezarezvani/claude-skills 235 個是最大社群 collection，jeffallan 的 SRE/DevOps 66 個 skills 對本 workspace 特別相關</li><li>生態系仍在加速增長，目前採用具有複利優勢</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>1,116 unique skills，500+ repositories，200+ authors</li><li>anthropics/skills：121,000 stars（17 official skills）</li><li>Trail of Bits：4,700+ stars（security）</li><li>Firecrawl：3,000+ stars（web scraping）</li><li>Sentry：2,500+ stars</li><li>jeffallan/claude-skills：66 個 SRE/DevOps/Terraform/K8s skills（與本 workspace 高度相關）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>文章格式為清單彙整，未提供安裝指令或相容性測試，部分 repo 可能已過時</li><li>1,116 這個數字是作者主觀計算，不同 skill 的品質差異極大</li><li>Part 6 DevOps/Infrastructure 的 jeffallan/claude-skills 值得深入研究（SRE 背景高度相關）</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9/10</td><td>直接提供 repo URLs，jeffallan SRE skills、Trail of Bits security skills 可立即評估整合</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>彙整工作本身有價值，但非原創，類似已存在的 awesome-claude-code</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>GitHub stars 提供相對可信度，但 1,116 計數方法未說明</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>列表式介紹，每個 skill 組描述過短</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>跨領域分類，所有 Claude Code 用戶均可參考</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.1/10</strong></td><td>9×0.3 + 6×0.2 + 6×0.2 + 5×0.15 + 8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skill <strong>理由</strong>：1,116 Skills 索引是 cc-workspace 擴充的重要資源，適合整合為 <code>skill-discovery</code> SKILL，專門指導從哪些 repo 尋找並評估新 Skills（特別是 DevOps/SRE 類）</p>',50)])])}const k=l(s,[["render",r]]);export{p as __pageData,k as default};
